from llama_stack_client import LlamaStackClient

client = LlamaStackClient(api_key='your-key')

def process_email(email_content: str, sender: str):
    prompt = f"""Analyze this email for intent:

Email: {email_content}
Sender: {sender}

Respond with JSON: {{"intent": "reply|forward|archive", "priority": "low|med|high", "key_points": ["list"]}}"""

    response = client.chat.completions.create(
        model='llama-3.2-90b',
        messages=[{"role": "user", "content": prompt}],
        tools=[{"type": "function", "function": {"name": "email_intent"}}]
    )
    return response.choices[0].message.content

def generate_draft(intent_data: dict, original_email: str):
    draft_prompt = f"""Generate professional email response:
Intent: {intent_data['intent']}
Key points: {intent_data['key_points']}
Original: {original_email}

Include attachments if referenced. JSON format: {{"subject": "", "body": "", "attachments": [], "recipients": []}}"""

    response = client.chat.completions.create(
        model='llama-3.2-90b',
        messages=[{"role": "user", "content": draft_prompt}],
        max_tokens=2000
    )
    return response.choices[0].message.content

def get_context(email_thread_id: str):
    memory_response = client.memory.retrieve(
        query=email_thread_id,
        limit=5,
        filter={'type': 'email_thread'}
    )

    context = [doc.content for doc in memory_response.documents]
    return {'history': context, 'associations': memory_response.associations}

