from functools import wraps

def vex_guardrail(agent_function):
    @wraps(agent_function)
    def wrapper(*args, **kwargs):
        llama_output = agent_function(*args, **kwargs)

        result = vex_client.verify(
            input={
                'agent_output': llama_output,
                'use_case': 'email_assistant',
                'risk_profile': 'high'
            },
            checks=[
                'pii_filtering',
                'tone_check',
                'recipient_validation',
                'confidentiality',
                'schema_conformance',
                'safety_override'
            ]
        )

        if result.passed:
            return llama_output
        else:
            return {'status': 'blocked', 'reason': result.issues}
    return wrapper

@vex_guardrail
def llama_email_agent(email_data):
